--
-- Table structure for table `flight_event`
--

DROP TABLE IF EXISTS `flight_event`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `flight_event` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'Unique ID per event',
  `call_sign` varchar(20) DEFAULT NULL COMMENT 'FK to flight.call_sign',
  `operation` enum('DEPARTURE','ARRIVAL') DEFAULT NULL COMMENT 'Flight operation type',

  `event_type` enum(
    'Scheduled_Off_Block',
    'Actual_Off_Block',
    'Movement_Area_Entrance',
    'Runway_Entrance',
    'Estimated_Take_Off',
    'Actual_Take_Off',
    'Scheduled_Take_Off',
    'Estimated_Landing',
    'Actual_Landing',
    'Runway_Exit',
    'Movement_Area_Exit',
    'Estimated_In_Block',
    'Actual_In_Block',
    'Boarding_Start',
    'North_Ramp_Enter',
    'North_Ramp_Exit',
    'South_Ramp_Enter',
    'South_Ramp_Exit'

  ) DEFAULT NULL COMMENT 'Type of operational event',
  `event_time` datetime DEFAULT NULL COMMENT 'Timestamp of event (US Pacific)',  
  `event_source` enum('AODB','ATC','Aerobahn','Filed') DEFAULT NULL COMMENT 'Data source of event',
  `location` varchar(50) DEFAULT NULL COMMENT 'Optional gate/runway/taxiway/ramp location',

  PRIMARY KEY (`id`),
  KEY `idx_event_call_sign` (`call_sign`),
  KEY `idx_event_type` (`event_type`),
  KEY `idx_event_time` (`event_time`)
) ENGINE=InnoDB AUTO_INCREMENT=32983 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='Detailed timeline of flight operational events';
/*!40101 SET character_set_client = @saved_cs_client */;

